24→    ".option no16bit        \n"
25→    "slli zero, zero, 0x1f  \n"
26→    "ebreak                 \n"
27→    "srai zero, zero, 0x7   \n"
28→    ".option pop            \n"
29→      : "+r"(a0) : "r"(a1) : "memory");
30→
31→  return a0;
32→}
