17→static bool _check_done;
18→
19→/* fdtable keeps track of the position of each file and is used to map stdin,
20→   stdout and stderr to STDIN_FILENO, STDOUT_FILENO and STDERR_FILENO.  */
21→
22→static struct fdentry fdtable[RISCV_MAX_OPEN_FILES];
23→
24→/* Initialize fdtable.  A handle of -1 denotes an empty entry.  */
25→
26→void
27→init_semihosting ()
28→{
29→  int i;
30→
31→  for (i=0; i<RISCV_MAX_OPEN_FILES; i++)
32→    fdtable[i].handle = -1;
33→
34→  /* Set up std streams.  */
35→  /* stdin.  */
36→  i = _open (":tt", O_RDONLY);
37→  fdtable[STDIN_FILENO].handle = fdtable[i].handle;
38→  fdtable[STDIN_FILENO].pos = 0;
39→
40→  /* stdout.  */
41→  i = _open (":tt", O_WRONLY|O_CREAT|O_TRUNC);
42→  fdtable[STDOUT_FILENO].handle = fdtable[i].handle;
43→  fdtable[STDOUT_FILENO].pos = 0;
44→
45→  /* stderr.  */
46→  i = _open (":tt", O_WRONLY|O_CREAT|O_APPEND);
47→  fdtable[STDERR_FILENO].handle = fdtable[i].handle;
48→  fdtable[STDERR_FILENO].pos = 0;
49→}
50→
51→/* Add entry to fdtable.  */
52→
53→int
54→__add_fdentry (int handle)
55→{
56→  if (!_check_done)
57→    {
58→      _check_done = true;
59→      init_semihosting ();
60→    }
61→  for (int i=0; i<RISCV_MAX_OPEN_FILES; i++)
62→    if (fdtable[i].handle == -1)
63→      {
64→	fdtable[i].handle = handle;
65→	fdtable[i].pos = 0;
66→	return i;
67→      }
68→  /* Too many open files.  */
69→  errno = ENFILE;
70→  return -1;
71→}
72→
73→/* Return the fdentry for file or NULL if not found.  */
74→
75→struct fdentry *
76→__get_fdentry (int file)
77→{
78→  if (!_check_done)
79→    {
80→      _check_done = true;
81→      init_semihosting ();
82→    }
83→  if (file<0 || file>=RISCV_MAX_OPEN_FILES || fdtable[file].handle == -1)
84→    {
85→      errno = EBADF;
86→      return NULL;
87→    }
88→  return &fdtable[file];
89→}
90→
91→/* Remove entry from fdtable.  */
92→
93→void
94→__remove_fdentry (int file)
95→{
96→  fdtable[file].handle = -1;
97→}
