13→
14→/* Set position in a file.  */
15→__attribute__((weak)) off_t
16→_lseek (int file, off_t offset, int dir)
17→{
18→  long data_block[2];
19→  long flen;
20→  long res;
21→  struct fdentry *fd;
22→  off_t abs_pos;
23→
24→  fd =__get_fdentry (file);
25→  if (fd == NULL)
26→    {
27→      errno = EBADF;
28→      return -1;
29→    }
30→
31→  if (dir == SEEK_CUR && offset == 0)
32→    return fd->pos;
33→
34→  data_block[0] = fd->handle;
35→
36→  switch (dir)
37→    {
38→      case SEEK_SET:
39→	abs_pos = offset;
40→	break;
41→      case SEEK_CUR:
42→	abs_pos = fd->pos + offset;
43→	break;
44→      case SEEK_END:
45→	data_block[1] = 0;
46→	flen = syscall_errno (SEMIHOST_flen, data_block);
47→	if (flen == -1)
48→	  return -1;
49→	abs_pos = flen + offset;
50→	break;
51→      default:
52→	errno = EINVAL;
53→	return -1;
54→    }
55→
56→  if (abs_pos < 0)
57→    {
58→      errno = EINVAL;
59→      return -1;
60→    }
61→
62→  data_block[1] = abs_pos;
63→  res = syscall_errno (SEMIHOST_seek, data_block);
64→  if (res == 0)
65→    {
66→      fd->pos = abs_pos;
67→      return abs_pos;
68→    }
69→  return __syscall_error ();
70→}
